+
+static int treecount(Dtlink_t* e)
+{	return e ? treecount(e->left) + treecount(e->right) + 1 : 0;
+}
+
+int dtsize(Dt_t* dt)
+{
+	UNFLATTEN(dt);
+
+	if (dt->data.size < 0) // !(dt->data.type & (DT_SET|DT_BAG))
+	{	if (dt->data.type & (DT_OSET|DT_OBAG))
