+}
+
+void agdtdisc(Agraph_t * g, Dict_t * dict, Dtdisc_t * disc)
+{
+    (void)g; /* unused */
+    if (disc && dtdisc(dict, NULL) != disc) {
+	dtdisc(dict, disc);
+    }
+    /* else unchanged, disc is same as old disc */
+}
+/// @defgroup cgraph_utils utilities
