+    for (const arrowname_t *arrowname = arrownames; arrowname->name;
+         arrowname++) {
+	namelen = strlen(arrowname->name);
+	if (startswith(name, arrowname->name)) {
+	    *flag |= arrowname->type;
+	    rest += namelen;
+	    break;
+	}
+    }
+    return rest;
