+    *flag = 0;
+    for (i = 0; *rest != '\0' && i < NUMB_OF_ARROW_HEADS; ) {
+	uint32_t f = ARR_TYPE_NONE;
+	next = rest;
+        rest = arrow_match_shape(next, &f);
+	if (f == ARR_TYPE_NONE) {
