+	endp -= 3;
+    }
+    sp[3] = ps[endp];
+    sp[2] = ps[endp + 1];
+    sp[1] = ps[endp + 2];
+    sp[0] = spl->ep;	/* ensure endpoint starts inside */
+
+    if (elen > 0) {
+	inside_context.a.p = &sp[0];
+	inside_context.a.r = &elen;
+	bezier_clip(&inside_context, inside, sp, true);
+    }
+
+    ps[endp] = sp[3];
+    ps[endp + 1] = sp[2];
+    ps[endp + 2] = sp[1];
+    ps[endp + 3] = sp[0];
+    return endp;
