+static void hsv2rgb(double h, double s, double v,
+			double *r, double *g, double *b)
+{
+    int i;
+    double f, p, q, t;
+
+    if (s <= 0.0) {		/* achromatic */
+	*r = v;
+	*g = v;
+	*b = v;
+    } else {
+	if (h >= 1.0)
+	    h = 0.0;
+	h = 6.0 * h;
+	i = (int) h;
+	f = h - i;
+	p = v * (1 - s);
+	q = v * (1 - s * f);
+	t = v * (1 - s * (1 - f));
+	switch (i) {
+	case 0:
+	    *r = v;
+	    *g = t;
+	    *b = p;
+	    break;
+	case 1:
+	    *r = q;
+	    *g = v;
+	    *b = p;
+	    break;
+	case 2:
+	    *r = p;
+	    *g = v;
+	    *b = t;
+	    break;
+	case 3:
+	    *r = p;
+	    *g = q;
+	    *b = v;
+	    break;
+	case 4:
+	    *r = t;
+	    *g = p;
+	    *b = v;
+	    break;
+	case 5:
+	    *r = v;
+	    *g = p;
+	    *b = q;
+	    break;
+	default:
+	    UNREACHABLE();
+	}
+    }
+}
+
+static void rgb2hsv(double r, double g, double b,
+		double *h, double *s, double *v)
+{
+
+    double rgbmin, rgbmax;
+    double rc, bc, gc;
+    double ht = 0.0, st = 0.0;
+
+    rgbmin = fmin(r, fmin(g, b));
+    rgbmax = fmax(r, fmax(g, b));
+
+    if (rgbmax > 0.0)
+	st = (rgbmax - rgbmin) / rgbmax;
+
+    if (st > 0.0) {
+	rc = (rgbmax - r) / (rgbmax - rgbmin);
+	gc = (rgbmax - g) / (rgbmax - rgbmin);
+	bc = (rgbmax - b) / (rgbmax - rgbmin);
+	if (is_exactly_equal(r, rgbmax))
+	    ht = bc - gc;
+	else if (is_exactly_equal(g, rgbmax))
+	    ht = 2 + rc - bc;
+	else if (is_exactly_equal(b, rgbmax))
+	    ht = 4 + gc - rc;
+	ht = ht * 60.0;
+	if (ht < 0.0)
+	    ht += 360.0;
+    }
+    *h = ht / 360.0;
+    *v = rgbmax;
+    *s = st;
+}
